import { PostPage } from '@kyokuya/react-layout-post'
import { graphql } from 'gatsby'
import React from 'react'
import type { PostBySlugQuery } from '@/types/gatsby-graphql'

interface IPageContext {
  /**
   * Url of pagination pages.
   */
  paginationUrl: string
  /**
   * Home url
   * @default '/'
   */
  homeUrl?: string
}

interface IProps {
  data: PostBySlugQuery
  pageContext: IPageContext
}

export default function PostLayout(props: IProps): React.ReactElement {
  const { paginationUrl, homeUrl } = props.pageContext
  const { previous, next, content, postItems } = props.data
  return (
    <PostPage
      paginationUrl={paginationUrl}
      homeUrl={homeUrl}
      postItems={postItems as any}
      content={content as any}
      previous={previous as any}
      next={next as any}
    />
  )
}

export const query = graphql`
  query PostBySlug(
    $contentType: String!
    $id: String!
    $previousPostId: String
    $nextPostId: String
  ) {
    content: markdownYozora(id: { eq: $id }) {
      title
      description
      createAt(formatString: "MMMM DD, YYYY")
      updateAt(formatString: "MMMM DD, YYYY")
      timeToRead(formatString: "m[min] s[s]")
      frontmatter2 {
        aplayer
        wechatThumbnail
      }
      toc {
        children
      }
      categories
      tags
      ast(shouldStrip: true)
      ecmaImports
      definitionMap
      footnoteDefinitionMap(preferReferences: true)
      fields {
        slug
      }
    }
    previous: markdownYozora(id: { eq: $previousPostId }) {
      title
      fields {
        slug
      }
    }
    next: markdownYozora(id: { eq: $nextPostId }) {
      title
      fields {
        slug
      }
    }
    postItems: allMarkdownYozora(
      filter: { fields: { contentType: { eq: $contentType } } }
    ) {
      nodes {
        title
        createAt(formatString: "YYYY-MM-DD")
        tags
        fields {
          slug
        }
      }
    }
  }
`
